import SwiftUI

struct ContentView: View {
    @State private var data: String = "Loading..."

    func fetchData() async {
        guard let url = URL(string: "https://jsonplaceholder.typicode.com/todos/1") else {
            data = "Invalid URL"
            return
        }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            if let decodedData = String(data: data, encoding: .utf8) {
                data = decodedData
            } else {
                data = "Failed to decode data"
            }
        } catch {
            data = "Error: \(error.localizedDescription)"
        }
    }

    var body: some View {
        Text(data)
            .onAppear {
                Task {
                    await fetchData()
                }
            }
    }
}
```
Giải thích: `async` và `await` cho phép chúng ta viết code asynchronous một cách tuần tự. `URLSession.shared.data(from:)` tải dữ liệu từ URL. `try await` xử lý các lỗi có thể xảy ra. `Task` tạo một task asynchronous để thực hiện `fetchData()`.

