import UIKit
import UserNotifications

class AppDelegate: UIResponder, UIApplicationDelegate, UNUserNotificationCenterDelegate {

    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        let center = UNUserNotificationCenter.current()
        center.delegate = self
        center.requestAuthorization(options: [.alert, .sound]) {
            (granted, error) in
            if granted {
                DispatchQueue.main.async {
                    application.registerForRemoteNotifications()
                }
            } else {
                print("Notification permission denied.")
            }
        }
        return true
    }

    func application(_ application: UIApplication, didRegisterForRemoteNotifications deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02.2hhx", $0) }.joined()
        print("Device Token: \(token)")
        // Gửi token này lên server của bạn
    }

    func userNotificationCenter(_ center: UNUserNotificationCenter, willPresent notification: UNNotification, options: UNNotificationPresentationOptions) let userInfo = notification.request.content.userInfo
        print("Foreground Notification: \(userInfo)")
        // Xử lý notification khi app ở foreground
    }

    func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: () -> Void) {
        let userInfo = response.notification.request.content.userInfo
        print("Background/Terminated Notification: \(userInfo)")
        // Xử lý notification khi app ở background hoặc terminated
        completionHandler()
    }
}
```
