import StoreKit

class ProductManager: ObservableObject {
    @Published var products: [Product] = []
    let productIDs = ["com.example.app.premiumfeature"]

    init() {
        fetchProducts()
    }

    func fetchProducts() {
        Task {
            do {
                products = try await Product.products(for: productIDs)
            } catch {
                print("Error fetching products: \(error)")
            }
        }
    }

    func purchaseProduct(product: Product) async throws {
        try await product.purchase(){
            result in
            switch result {
            case .success(_):
                print("Purchase successful!")
            case .failure(let error):
                print("Purchase failed: \(error)")
            }
        }
    }

    func restorePurchases() async throws {
        try await AppStoreUtil.restorePurchases(){
            result in
            switch result {
            case .success(_):
                print("Restore successful!")
                fetchProducts()
            case .failure(let error):
                print("Restore failed: \(error)")
            }
        }
    }
}

class AppStoreUtil {
    static func restorePurchases(completion: @escaping (Result<[String], Error>) -> Void) {
        AppStore.shared.restorePurchases(completion: completion)
    }
}
```
Giải thích: `ProductManager` quản lý các sản phẩm in-app purchase. `fetchProducts` sử dụng `Product.products(for:)` để lấy danh sách sản phẩm. `purchaseProduct` sử dụng `product.purchase()` để bắt đầu quá trình mua. `restorePurchases` sử dụng `AppStore.shared.restorePurchases()` để khôi phục các giao dịch đã mua.  StoreKit 2 sử dụng async/await để đơn giản hóa code.

