import Combine
import Foundation

struct DataFetcher {
    static func fetchData(from url: URL) -> AnyPublisher<Data, Error> {
        URLSession.shared.dataTask(with: url)
            .publisher
            .tryMap { (data, response) -> Data in
                guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                    throw URLError(.badServerResponse)
                }
                return data
            }
            .catch { error in
                Fail(error: error).eraseToAnyPublisher()
            }
    }
}

class ViewModel {
    @Published var data: Data? = nil
    @Published var error: Error? = nil

    private var cancellables = Set<AnyCancellable>()

    init(url: URL) {
        DataFetcher.fetchData(from: url)
            .sink(receiveCompletion: {
                completion in
                switch completion {
                case .finished: break
                case .failure(let error): self.error = error
                }
            }, receiveValue: {
                data in
                self.data = data
            })
            .store(in: &cancellables)
    }
}

struct ContentView: View {
    @ObservedObject var viewModel: ViewModel

    var body: some View {
        VStack {
            if let data = viewModel.data {
                Text("Data received: \(data.count) bytes")
            } else if let error = viewModel.error {
                Text("Error: \(error.localizedDescription)")
            } else {
                Text("Loading...")
            }
        }
    }
}
```
Giải thích: `DataFetcher` sử dụng `URLSession` để tải dữ liệu và trả về một `Publisher`. `tryMap` kiểm tra mã trạng thái HTTP và trả về dữ liệu nếu thành công, nếu không sẽ ném lỗi. `catch` xử lý bất kỳ lỗi nào xảy ra trong quá trình tải dữ liệu. `ViewModel` sử dụng `sink` để subscribe vào publisher và cập nhật `data` hoặc `error`.
